const ENG={"Hegganahalli":{"name":"Sri H. Eshwaraiah","designation":"Assistant Executive Engineer","phone":"9480684488","address":"Hegganahalli Subdivision Office, Dasarahalli","verified":false},"Shanthi Nagar":{"name":"Venkateshiah","designation":"Engineering Ward Office","phone":"9900623513","address":"Engineering Ward Office, Ejipura, 17th Main Road, 5th Block","verified":false},"Domlur":{"name":"Rajendra","designation":"Ward Engineer","phone":"9945072721","address":"Ward Office, 17th F Cross, Indiranagar 1st Stage, Bangalore-38","verified":false},"Banasavadi":{"name":"Venkatesh","designation":"Ward Engineer","phone":"9986555521","address":"Ward Office Banaswadi, Main Road, Bus Stand, 1st Block HRBR Layout","verified":false}};

// ---- palette ----
const C = {
  ink:"#1B2A4A", paper:"#FBFAF7", surface:"#FFFFFF", slate:"#3A4256",
  line:"#E6E1D8", amber:"#E0922F", amberDk:"#B5701A", teal:"#1F7A6E",
  clay:"#9A8C7A", clayBg:"#F2EEE6", mut:"#8A8478"
};
const mono = "ui-monospace, SFMono-Regular, Menlo, monospace";
const disp = "'Helvetica Neue', Arial, sans-serif";

function acNum(ac){ const m=(ac||"").match(/(\d+)/); return m?m[1]:null; }
function corpForWard(w){
  const n = acNum(w.ac); if(!n) return null;
  return GBA.corporations.find(c => c.assembly_constituencies.some(a => a.startsWith(n+"-"))) || null;
}
const CORP_TINT = {KENDRA:"#1F7A6E",PURVA:"#3A6EA5",PASHCHIMA:"#B5701A",UTTARA:"#7A5BA8",DAKSHINA:"#C04A4A"};

function Pill({children, bg, fg, title}){
  return <span title={title} style={{background:bg,color:fg,fontFamily:mono,fontSize:11,
    padding:"2px 7px",borderRadius:5,whiteSpace:"nowrap",lineHeight:1.6,fontWeight:600}}>{children}</span>;
}

function LineageRail({w, corp}){
  const node = (label, sub, color, active) => (
    <div style={{flex:1,minWidth:0}}>
      <div style={{fontSize:10,letterSpacing:.8,textTransform:"uppercase",color:C.mut,marginBottom:4}}>{label}</div>
      <div style={{border:`1px solid ${active?color:C.line}`,borderRadius:8,padding:"8px 10px",
        background:active?color+"12":C.surface,minHeight:46}}>
        <div style={{fontFamily:mono,fontSize:13,fontWeight:700,color:active?color:C.slate,
          overflow:"hidden",textOverflow:"ellipsis"}}>{sub||"—"}</div>
      </div>
    </div>
  );
  const olds = (w.old_wards&&w.old_wards.length)? w.old_wards.join(", ") : "not mapped";
  return (
    <div style={{display:"flex",alignItems:"flex-end",gap:6,marginTop:14,marginBottom:4}}>
      {node("Old · BBMP 198", olds, C.clay, false)}
      <div style={{color:C.mut,paddingBottom:14,fontFamily:mono}}>→</div>
      {node("New · BBMP 225", `#${w.new_no} ${w.new_name}`, C.ink, true)}
      <div style={{color:C.mut,paddingBottom:14,fontFamily:mono}}>→</div>
      {node("GBA · 369", corp? corp.name : "pending import", corp?CORP_TINT[corp.code]:C.mut, !!corp)}
    </div>
  );
}

function EngineerCard({ward, eng, onEdit}){
  const key = ward.eng_subdiv;
  const e = eng[key] || {name:"",designation:"Assistant Executive Engineer",phone:"",address:"",verified:false};
  const [edit,setEdit]=useState(false);
  const [f,setF]=useState(e);
  React.useEffect(()=>{ setF(eng[key]||{name:"",designation:"Assistant Executive Engineer",phone:"",address:"",verified:false}); setEdit(false); },[key]);
  const has = f.name||f.phone;
  const tel = (f.phone||"").replace(/\D/g,"");
  return (
    <div style={{border:`1px solid ${C.line}`,borderRadius:12,overflow:"hidden",marginTop:16}}>
      <div style={{background:C.amber+"18",padding:"9px 14px",display:"flex",justifyContent:"space-between",alignItems:"center",borderBottom:`1px solid ${C.amber}33`}}>
        <div style={{fontSize:11,letterSpacing:1,textTransform:"uppercase",color:C.amberDk,fontWeight:700}}>Engineering Sub-Division Officer</div>
        <button onClick={()=>setEdit(v=>!v)} style={{background:"none",border:`1px solid ${C.amber}`,color:C.amberDk,
          borderRadius:6,fontSize:11,padding:"3px 9px",cursor:"pointer",fontWeight:600}}>{edit?"Done":"Edit"}</button>
      </div>
      <div style={{padding:14}}>
        <div style={{fontSize:12,color:C.mut,marginBottom:8}}>Sub-division&nbsp;
          <span style={{fontFamily:mono,color:C.slate,fontWeight:700}}>{key}</span>
          {!f.verified && has && <span style={{marginLeft:8,fontSize:10,color:C.clay}}>· unverified seed</span>}
        </div>
        {edit ? (
          <div style={{display:"grid",gap:8}}>
            {["name","designation","phone","address"].map(k=>(
              <input key={k} value={f[k]||""} placeholder={k[0].toUpperCase()+k.slice(1)}
                onChange={ev=>setF({...f,[k]:ev.target.value})}
                style={{border:`1px solid ${C.line}`,borderRadius:7,padding:"8px 10px",fontSize:13,fontFamily:k==="phone"?mono:disp,color:C.slate}}/>
            ))}
            <button onClick={()=>{onEdit(key,{...f,verified:true}); setEdit(false);}}
              style={{background:C.ink,color:"#fff",border:"none",borderRadius:7,padding:"8px",fontSize:13,fontWeight:600,cursor:"pointer"}}>Save officer</button>
          </div>
        ) : has ? (
          <div>
            <div style={{fontSize:18,fontWeight:700,color:C.ink,fontFamily:disp}}>{f.name||"—"}</div>
            <div style={{fontSize:12,color:C.slate,marginBottom:6}}>{f.designation}</div>
            {f.address && <div style={{fontSize:12,color:C.slate,lineHeight:1.5,marginBottom:10}}>{f.address}</div>}
            <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
              {tel && <a href={`tel:${tel}`} style={{textDecoration:"none",background:C.ink,color:"#fff",
                borderRadius:8,padding:"8px 14px",fontSize:13,fontWeight:600,fontFamily:mono}}>Call {f.phone}</a>}
              {tel && <a href={`https://wa.me/91${tel.slice(-10)}`} target="_blank" rel="noreferrer"
                style={{textDecoration:"none",background:C.teal,color:"#fff",borderRadius:8,padding:"8px 14px",fontSize:13,fontWeight:600}}>WhatsApp</a>}
            </div>
          </div>
        ) : (
          <div style={{fontSize:13,color:C.mut,fontStyle:"italic"}}>No officer on record. Tap <b>Edit</b> to add — these get scraped/filled as GBA publishes assignments.</div>
        )}
      </div>
    </div>
  );
}

function Detail({w, eng, onEdit}){
  if(!w) return (
    <div style={{display:"flex",alignItems:"center",justifyContent:"center",height:"100%",padding:30,
      color:C.mut,textAlign:"center",fontSize:14}}>
      Select a ward to trace it across the three systems and reach its engineer.
    </div>
  );
  const corp = corpForWard(w);
  const row=(k,v)=> <div style={{display:"flex",justifyContent:"space-between",gap:10,padding:"7px 0",borderBottom:`1px solid ${C.line}`}}>
    <span style={{fontSize:12,color:C.mut}}>{k}</span><span style={{fontSize:13,color:C.slate,fontWeight:600,textAlign:"right"}}>{v}</span></div>;
  return (
    <div style={{padding:"4px 2px"}}>
      <div style={{display:"flex",alignItems:"baseline",gap:10}}>
        <span style={{fontFamily:mono,fontSize:30,fontWeight:800,color:C.ink}}>#{w.new_no}</span>
        <span style={{fontSize:20,fontWeight:700,color:C.ink,fontFamily:disp}}>{w.new_name}</span>
      </div>
      <div style={{marginTop:4}}>
        {corp && <Pill bg={CORP_TINT[corp.code]+"1A"} fg={CORP_TINT[corp.code]}>{corp.name}</Pill>}
        <span style={{marginLeft:8}}><Pill bg={C.clayBg} fg={C.clay}>{w.zone} Zone</Pill></span>
      </div>
      <LineageRail w={w} corp={corp}/>
      <div style={{marginTop:14}}>
        {row("Approx. properties", w.property_count.toLocaleString("en-IN"))}
        {row("Assembly Constituency", w.ac)}
        {row("Division", w.division)}
        {row("Old sub-division", w.old_subdiv)}
        {row("Engineering sub-division", w.eng_subdiv+`  (SL ${w.eng_subdiv_sl})`)}
        {row("GBA corporation", corp? corp.name : "import pending")}
      </div>
      <EngineerCard ward={w} eng={eng} onEdit={onEdit}/>
    </div>
  );
}

function Cascade({onPick}){
  const [zone,setZone]=useState(""); const [ac,setAc]=useState(""); const [div,setDiv]=useState(""); const [sub,setSub]=useState("");
  const zones=[...new Set(BBMP.map(w=>w.zone))].sort();
  const acs=[...new Set(BBMP.filter(w=>w.zone===zone).map(w=>w.ac))].sort();
  const divs=[...new Set(BBMP.filter(w=>w.zone===zone&&w.ac===ac).map(w=>w.division))].sort();
  const subs=[...new Set(BBMP.filter(w=>w.zone===zone&&w.ac===ac&&w.division===div).map(w=>w.eng_subdiv))].sort();
  const wards=BBMP.filter(w=>w.zone===zone&&w.ac===ac&&w.division===div&&w.eng_subdiv===sub).sort((a,b)=>a.new_no-b.new_no);
  const Sel=({label,val,set,opts,dis})=>(
    <div style={{marginBottom:10}}>
      <div style={{fontSize:10,letterSpacing:.8,textTransform:"uppercase",color:C.mut,marginBottom:4}}>{label}</div>
      <select value={val} disabled={dis} onChange={e=>set(e.target.value)}
        style={{width:"100%",padding:"9px 10px",borderRadius:8,border:`1px solid ${C.line}`,
        fontSize:13,color:dis?C.mut:C.slate,background:dis?C.clayBg:C.surface,fontFamily:disp}}>
        <option value="">{dis?"—":"Select "+label.toLowerCase()}</option>
        {opts.map(o=><option key={o} value={o}>{o}</option>)}
      </select>
    </div>
  );
  return (
    <div>
      <Sel label="Zone (BBMP)" val={zone} set={v=>{setZone(v);setAc("");setDiv("");setSub("");}} opts={zones} dis={false}/>
      <Sel label="Assembly Constituency" val={ac} set={v=>{setAc(v);setDiv("");setSub("");}} opts={acs} dis={!zone}/>
      <Sel label="Division" val={div} set={v=>{setDiv(v);setSub("");}} opts={divs} dis={!ac}/>
      <Sel label="Engineering Sub-division" val={sub} set={setSub} opts={subs} dis={!div}/>
      {sub && <div style={{marginTop:6}}>
        {wards.map(w=><WardRow key={w.new_no} w={w} onPick={onPick}/>)}
      </div>}
    </div>
  );
}

function WardRow({w,onPick,active}){
  const corp=corpForWard(w);
  return (
    <button onClick={()=>onPick(w)} style={{width:"100%",textAlign:"left",background:active?C.ink+"0A":C.surface,
      border:`1px solid ${active?C.ink:C.line}`,borderRadius:9,padding:"9px 11px",marginBottom:7,cursor:"pointer",
      display:"flex",alignItems:"center",gap:10}}>
      <span style={{fontFamily:mono,fontSize:13,fontWeight:700,color:C.ink,minWidth:34}}>#{w.new_no}</span>
      <span style={{flex:1,minWidth:0}}>
        <span style={{fontSize:14,fontWeight:600,color:C.slate}}>{w.new_name}</span>
        <span style={{display:"block",fontSize:11,color:C.mut,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>
          {w.eng_subdiv} · {w.old_wards.length? w.old_wards.join(", "):"new"}</span>
      </span>
      {corp && <span style={{width:8,height:8,borderRadius:8,background:CORP_TINT[corp.code]}}/>}
    </button>
  );
}

function GBAView(){
  return (
    <div style={{display:"grid",gap:12}}>
      <div style={{fontSize:13,color:C.slate,lineHeight:1.6,background:C.clayBg,padding:"12px 14px",borderRadius:10}}>
        The 2026 Greater Bengaluru Authority order splits the city into <b>5 corporations · 369 wards · 50 divisions · 150 sub-divisions</b>.
        Ward-level rows are in Kannada in the source annexures and are slotted for import — corporation mapping below is derived from each ward's assembly constituency.
      </div>
      {GBA.corporations.map(c=>{
        const mapped=BBMP.filter(w=>corpForWard(w)&&corpForWard(w).code===c.code).length;
        return (
          <div key={c.code} style={{border:`1px solid ${C.line}`,borderRadius:12,padding:14,borderLeft:`4px solid ${CORP_TINT[c.code]}`}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"baseline"}}>
              <div style={{fontSize:17,fontWeight:700,color:C.ink,fontFamily:disp}}>{c.name} <span style={{color:C.mut,fontWeight:400,fontSize:14}}>{c.name_kn}</span></div>
              <Pill bg={CORP_TINT[c.code]+"1A"} fg={CORP_TINT[c.code]}>Annexure {c.annexure}</Pill>
            </div>
            <div style={{display:"flex",gap:18,margin:"10px 0",flexWrap:"wrap"}}>
              {[["Wards",c.wards],["Divisions",c.divisions],["Sub-divisions",c.subdivisions]].map(([k,v])=>(
                <div key={k}><div style={{fontFamily:mono,fontSize:20,fontWeight:800,color:C.ink}}>{v}</div>
                  <div style={{fontSize:10,letterSpacing:.6,textTransform:"uppercase",color:C.mut}}>{k}</div></div>
              ))}
            </div>
            <div style={{fontSize:12,color:C.slate,lineHeight:1.7}}>
              <span style={{color:C.mut}}>Assembly constituencies: </span>{c.assembly_constituencies.join(" · ")}
            </div>
            <div style={{marginTop:8,fontSize:11,color:C.mut}}>
              {mapped} BBMP-225 wards linked via constituency · <span style={{color:C.amberDk,fontWeight:600}}>{c.wards} GBA ward names — import pending</span>
            </div>
          </div>
        );
      })}
    </div>
  );
}

export default function App(){
  const [tab,setTab]=useState("search");
  const [q,setQ]=useState("");
  const [sel,setSel]=useState(null);
  const [eng,setEng]=useState(ENG);
  const onEdit=(k,v)=>setEng(p=>({...p,[k]:v}));

  const results=useMemo(()=>{
    const s=q.trim().toLowerCase(); if(!s) return [];
    return BBMP.filter(w=>{
      const hay=[w.new_no,w.new_name,w.eng_subdiv,w.division,w.ac,w.zone,w.old_subdiv,(w.old_wards||[]).join(" ")].join(" ").toLowerCase();
      return hay.includes(s);
    }).sort((a,b)=>a.new_no-b.new_no).slice(0,60);
  },[q]);

  const Tab=({id,label})=>(
    <button onClick={()=>setTab(id)} style={{background:tab===id?C.ink:"transparent",color:tab===id?"#fff":C.slate,
      border:`1px solid ${tab===id?C.ink:C.line}`,borderRadius:8,padding:"7px 14px",fontSize:13,fontWeight:600,cursor:"pointer"}}>{label}</button>
  );

  return (
    <div style={{fontFamily:disp,background:C.paper,minHeight:"100vh",color:C.slate}}>
      <div style={{maxWidth:1080,margin:"0 auto",padding:"22px 18px 60px"}}>
        {/* header */}
        <div style={{borderBottom:`2px solid ${C.ink}`,paddingBottom:14,marginBottom:18}}>
          <div style={{fontSize:11,letterSpacing:2,textTransform:"uppercase",color:C.amberDk,fontWeight:700}}>Bengaluru Ward Lineage Tracker</div>
          <div style={{fontSize:26,fontWeight:800,color:C.ink,fontFamily:disp,marginTop:2,lineHeight:1.1}}>BBMP 198 → 225 → GBA 369</div>
          <div style={{display:"flex",gap:14,marginTop:8,flexWrap:"wrap"}}>
            <Pill bg={C.clayBg} fg={C.clay}>198 old wards</Pill>
            <Pill bg={C.ink+"12"} fg={C.ink}>225 notified wards · loaded</Pill>
            <Pill bg={C.teal+"14"} fg={C.teal}>369 GBA wards · structure</Pill>
          </div>
        </div>
        {/* tabs + search */}
        <div style={{display:"flex",gap:8,marginBottom:14,flexWrap:"wrap"}}>
          <Tab id="search" label="Search"/><Tab id="browse" label="Browse cascade"/><Tab id="gba" label="GBA structure"/>
        </div>

        <div style={{display:"grid",gridTemplateColumns:"minmax(0,1fr) minmax(0,1.05fr)",gap:18}} className="wt-grid">
          {/* left */}
          <div>
            {tab==="search" && <>
              <input autoFocus value={q} onChange={e=>setQ(e.target.value)}
                placeholder="Ward no, name, locality, sub-division… e.g. 'HSR', '104', 'Arakere'"
                style={{width:"100%",padding:"12px 14px",borderRadius:10,border:`1px solid ${C.line}`,fontSize:15,
                  color:C.slate,boxSizing:"border-box",marginBottom:12}}/>
              {q && <div style={{fontSize:11,color:C.mut,marginBottom:8}}>{results.length} match{results.length!==1?"es":""}{results.length===60?" (showing first 60)":""}</div>}
              {!q && <div style={{fontSize:13,color:C.mut,lineHeight:1.6,padding:"8px 2px"}}>
                Searches across all naming systems at once — old 198 names, new 225 names &amp; numbers, engineering sub-divisions, divisions and constituencies.
              </div>}
              {results.map(w=><WardRow key={w.new_no} w={w} onPick={setSel} active={sel&&sel.new_no===w.new_no}/>)}
            </>}
            {tab==="browse" && <Cascade onPick={setSel}/>}
            {tab==="gba" && <GBAView/>}
          </div>
          {/* right */}
          {tab!=="gba" && <div style={{background:C.surface,border:`1px solid ${C.line}`,borderRadius:14,padding:18,minHeight:340}}>
            <Detail w={sel} eng={eng} onEdit={onEdit}/>
          </div>}
        </div>

        <div style={{marginTop:26,fontSize:11,color:C.mut,lineHeight:1.6,borderTop:`1px solid ${C.line}`,paddingTop:12}}>
          Data: BBMP Notified 225 Wards (Annexure-1) · GBA 5-Corporation Memo (06-03-2026). Engineer contacts are seeded from older official BBMP directories and are editable; GBA assignments are not yet published. Verify against source before official use.
        </div>
      </div>
      <style>{`
        @media (max-width: 760px){ .wt-grid{ grid-template-columns: 1fr !important; } }
        button:focus-visible, a:focus-visible, select:focus-visible, input:focus-visible{ outline:2px solid ${C.amber}; outline-offset:2px; }
        select, input{ font-family:inherit; }
      `}</style>
    </div>
  );
}
